public class SimpleWhileLoop {
  public static void main(String[] args) {
    int counter = 1;
    while (counter <= 5) {
      System.out.println("Təkrar: " + counter);
      counter++;
    }
  }
}
// Çıxış:
// Təkrar: 1
// Təkrar: 2
// Təkrar: 3
// Təkrar: 4
// Təkrar: 5

public class DoWhileLoop {
  public static void main(String[] args) {
    int counter = 1;
    do {
      System.out.println("Təkrar: " + counter);
      counter++;
    } while (counter <= 3);
  }
}
// Çıxış:
// Təkrar: 1
// Təkrar: 2
// Təkrar: 3

public class NestedWhileLoop {
  public static void main(String[] args) {
    int i = 1;
    while (i <= 3) {
      int j = 1;
      while (j <= 3) {
        System.out.println("i: " + i + ", j: " + j);
        j++;
      }
      i++;
    }
  }
}
// Çıxış:
// i: 1, j: 1
// i: 1, j: 2
// i: 1, j: 3
// i: 2, j: 1
// i: 2, j: 2
// i: 2, j: 3
// i: 3, j: 1
// i: 3, j: 2
// i: 3, j: 3

public class BreakContinueWhile {
  public static void main(String[] args) {
    int counter = 1;
    while (counter <= 5) {
      if (counter == 3) {
        counter++;
        continue; // 3-ü buraxır
      }
      if (counter == 5) {
        break; // Dövrü dayandırır
      }
      System.out.println("Dəyər: " + counter);
      counter++;
    }
  }
}
// Çıxış:
// Dəyər: 1
// Dəyər: 2
// Dəyər: 4

public class StockCheck {
  public static void main(String[] args) {
    int stock = 5;
    int sold = 0;
    while (stock > 0) {
      sold++;
      stock--;
      System.out.println("Satılan məhsul: " + sold + ", Qalan stok: " + stock);
    }
    System.out.println("Stok tükəndi!");
  }
}
// Çıxış:
// Satılan məhsul: 1, Qalan stok: 4
// Satılan məhsul: 2, Qalan stok: 3
// Satılan məhsul: 3, Qalan stok: 2
// Satılan məhsul: 4, Qalan stok: 1
// Satılan məhsul: 5, Qalan stok: 0
// Stok tükəndi!

